import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as r,e as o}from"./app-be253e4c.js";const t={},d=o('<h1 id="同步模块模式" tabindex="-1"><a class="header-anchor" href="#同步模块模式" aria-hidden="true">#</a> 同步模块模式</h1><p><code>同步模块模式</code>是请求发出后，无论模块是否存在，立即执行后续的逻辑，实现模块开发中对模块的立即引用， 模块化是将复杂的系统分解为高内聚、低耦合模块。</p><p><strong>同步模块模式不属于一般定义的23种设计模式的范畴，通常将其看作广义上的架构型设计模式。</strong></p><h2 id="基本介绍" tabindex="-1"><a class="header-anchor" href="#基本介绍" aria-hidden="true">#</a> 基本介绍</h2><p>同步模块模式通常用来解决如下场景的问题，随着页面功能的增加，系统的业务逻辑越来越复杂，多人开发的功能经常耦合在一起，有时项目经理提出的需求，分配给多人实现的时候，常常因为某一处功能耦合了多人的代码，从而出现排队修改的现象。<br> 通过使用模块化来分解复杂的系统可以很好地去解决这个问题，要想实现模块化开发，首先就需要有一个模块管理器，其管理着模块的创建与调度，对于模块的调用分为两类，第一类就是同步的模块调度，实现相对比较简单，不需要考虑模块间的异步加载，第二类的异步模块调度就比较繁琐，其可以实现对模块的加载调度。</p><h2 id="代码实现" tabindex="-1"><a class="header-anchor" href="#代码实现" aria-hidden="true">#</a> 代码实现</h2>',6),c=[d];function n(s,h){return a(),r("div",null,c)}const l=e(t,[["render",n],["__file","sync-module-mode.html.vue"]]);export{l as default};
